import{c as a,Q as l,j as r,m as o}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"How do I roll back a release?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/admin/rollback-release.md","filePath":"guide/recipes/admin/rollback-release.md","lastUpdated":1779094756000}'),t={name:"guide/recipes/admin/rollback-release.md"};function s(i,e,n,c,d,h){return l(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="how-do-i-roll-back-a-release" tabindex="-1">How do I roll back a release? <a class="header-anchor" href="#how-do-i-roll-back-a-release" aria-label="Permalink to &quot;How do I roll back a release?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Platform Admin</strong> or <strong>Infra Ops</strong></p></div><p>Rolling back a release re-deploys the previous version&#39;s pinned images and env vars across every environment the release reached. It runs through the same pipeline, so approvals and triggers still apply.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open the release detail page.</li><li>Click <strong>Roll Back</strong> in the actions menu.</li><li>The rollback dialog shows which environments will revert and to which prior version.</li><li>Confirm.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>A rollback release is created with type <strong>Rollback</strong> and is linked to the original. It runs through the pipeline:</p><ul><li>Deployed environments revert in reverse order (production first, then staging, then dev) by default.</li><li>Approvals are required only if your release configuration says so for rollback releases.</li><li>The original release moves to status <strong>Rolled Back</strong> once the rollback completes.</li></ul><div class="warning custom-block"><p class="custom-block-title">Rollback isn&#39;t always reversible</p><p>If the original release ran a one-way data migration, the rollback can&#39;t undo that. Review what the release changed before clicking.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./create-release">How do I create a release?</a></li><li><a href="./archive-release">How do I archive or unarchive a release?</a></li></ul>',11)])])}const m=a(t,[["render",s]]);export{u as __pageData,m as default};
